diff --git a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
index 56bfc8432cbb..5fdb83a8c787 100644
--- a/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
+++ b/llvm/lib/Transforms/IPO/FunctionAttrs.cpp
@@ -122,6 +122,13 @@ static void addLocAccess(MemoryEffects &ME, const MemoryLocation &Loc,
     return;

   const Value *UO = getUnderlyingObjectAggressive(Loc.Ptr);
+  // If getUnderlyingObjectAggressive returns null (e.g., due to cyclic PHIs),
+  // conservatively treat as unidentified object.
+  if (!UO) {
+    ME |= MemoryEffects::argMemOnly(MR);
+    ME |= MemoryEffects(IRMemLocation::Other, MR);
+    return;
+  }
   if (isa<AllocaInst>(UO))
     return;
   if (isa<Argument>(UO)) {

